module sr_latch (
    input wire S,
    input wire R,
    input wire clk,
    output reg obf_Q,
    output reg Q_bar
);
    always @(posedge clk) begin
        if (S && !R) begin
            obf_Q <= 1;
            Q_bar <= 0;
        end else if (!S && R) begin
            obf_Q <= 0;
            Q_bar <= 1;
        end else if (!S && !R) begin
            // Hold state
            obf_Q <= obf_Q;
            Q_bar <= Q_bar;
        end else begin
            // Undefined state, can be treated as a reset
            obf_Q <= 0;
            Q_bar <= 1;
        end
    end
endmodule
